def test_custom_leaky_relu(self):
    def lrelu(x, alpha=0.01):
        return tf.nn.relu(x) - alpha * tf.nn.relu(-x)

    x = tf.constant([-1.0, 0.0, 1.0], dtype=tf.float32)
    result = lrelu(x)
