target_test:
def test_case_graph_mode(self):
    # Test tf.case in graph mode with tf.function
    x = tf.constant(1)

    @tf.function
    def f():
        return tf.case([
            (tf.equal(x, 1), lambda: tf.constant(2)),
            (tf.equal(x, 2), lambda: tf.constant(3))
        ], default=lambda: tf.constant(1), exclusive=True)

    result = f()
    self.assertEqual(result.numpy(), 2)

def test_case_conditional_update(self):
    # Test tf.case for conditional tensor update
    global_step = tf.Variable(0, dtype=tf.int64)
    learning_rate = tf.Variable(0.1, dtype=tf.float32, name='learning_rate')

    cases = [
        (tf.equal(global_step, 2), lambda: tf.constant(0.01, dtype=tf.float32)),
        (tf.equal(global_step, 4), lambda: tf.constant(0.001, dtype=tf.float32))
    ]

    update = tf.case(cases, default=lambda: learning_rate)
    updated_learning_rate = tf.assign(learning_rate, update)

    @tf.function
    def update_lr():
        return updated_learning_rate

    # Initialize variables
    tf.compat.v1.global_variables_initializer().run()

    # Test the learning rate update
    for step in range(6):
        tf.compat.v1.assign(global_step, step).eval()
        lr = update_lr().numpy()
        if step == 2:
            self.assertAlmostEqual(lr, 0.01)
        elif step == 4:
            self.assertAlmostEqual(lr, 0.001)
        else:
            self.assertAlmostEqual(lr, 0.1)

