def test_stateful_function(self):
    state = {'counter': 0}

    def increment_counter(x):
        state['counter'] += 1
        return x + state['counter']

    x = tf.constant(1.0, dtype=tf.float32)
    result1 = tf.numpy_function(func=increment_counter, inp=[x], Tout=tf.float32)
    result2 = tf.numpy_function(func=increment_counter, inp=[x], Tout=tf.float32)
    self.assertEqual(result1.numpy(), 2.0)
    self.assertEqual(result2.numpy(), 3.0)

def test_stateless_function(self):
    def add_one(x):
        return x + 1

    x = tf.constant(1.0, dtype=tf.float32)
    result = tf.numpy_function(func=add_one, inp=[x], Tout=tf.float32, stateful=False)
    self.assertEqual(result.numpy(), 2.0)

def test_multiple_outputs(self):
    def split_sum_and_product(x, y):
        return np.add(x, y), np.multiply(x, y)

    x = tf.constant([1.0, 2.0, 3.0], dtype=tf.float32)
    y = tf.constant([4.0, 5.0, 6.0], dtype=tf.float32)
    sum_result, product_result = tf.numpy_function(
        func=split_sum_and_product, inp=[x, y], Tout=[tf.float32, tf.float32])
    expected_sum = np.array([5.0, 7.0, 9.0], dtype=np.float32)
    expected_product = np.array([4.0, 10.0, 18.0], dtype=np.float32)
    self.assertTrue(np.array_equal(sum_result.numpy(), expected_sum))
    self.assertTrue(np.array_equal(product_result.numpy(), expected_product))

