class TestMirroredStrategy(unittest.TestCase):

    def setUp(self):
        # Set up the strategy for each test
        self.strategy = tf.distribute.MirroredStrategy(devices=["/gpu:0", "/gpu:1"])

    def test_device_assignment(self):
        # Test if the devices are correctly assigned
        with self.strategy.scope():
            def step_fn():
                i = tf.distribute.get_replica_context().replica_id_in_sync_group
                return tf.identity(i)

            per_replica_result = self.strategy.run(step_fn)
            devices = [result.device for result in self.strategy.experimental_local_results(per_replica_result)]
            self.assertIn("/device:GPU:0", devices[0])
            self.assertIn("/device:GPU:1", devices[1])

