target_test:
def test_while_loop_with_jit_compile(self):
    x = tf.reshape(tf.range(25, dtype=tf.float32), [5, 5])
    row_lengths = tf.constant([2, 1, 2])
    ragged_tensor = tf.RaggedTensor.from_row_lengths(x, row_lengths)

    @tf.function(autograph=False, jit_compile=True)
    def while_loop_works():
        num_rows = ragged_tensor.nrows()

        def cond(i, _):
            return i < num_rows

        def body(i, running_total):
            return i + 1, running_total + tf.reduce_sum(ragged_tensor[i])

        _, total = tf.while_loop(cond, body, [0, 0.0])
        return total

    result = while_loop_works()
    self.assertEqual(result.numpy(), 300.0)

def test_conditional_execution_with_tf_case(self):
    x = tf.constant(1)

    def a():
        tf.print("a")
        return tf.constant(2)

    def b():
        tf.print("b")
        return tf.constant(3)

    def c():
        tf.print("c")
        return tf.constant(4)

    def d():
        tf.print("default")
        return tf.constant(1)

    @tf.function
    def f():
        return tf.case([
            (tf.equal(x, 1), a),
            (tf.equal(x, 2), b),
            (tf.equal(x, 2), c)
        ], default=d, exclusive=True)

    result = f()
    self.assertEqual(result.numpy(), 2)

