def test_initialize_tpu_system_success(self):
    """Test successful initialization of TPU system."""
    try:
        tf.config.experimental_connect_to_cluster(self.cluster_resolver)
        topology = tf.tpu.experimental.initialize_tpu_system(self.cluster_resolver)
        self.assertIsNotNone(topology, "TPU topology should not be None after initialization.")
