        self.fail(f"Initialization failed with exception: {e}")

def test_initialize_tpu_system_inside_function(self):
    """Test initialization inside a tf.function."""
    @tf.function
    def initialize_tpu():
        tf.config.experimental_connect_to_cluster(self.cluster_resolver)
        return tf.tpu.experimental.initialize_tpu_system(self.cluster_resolver)

    try:
        serialized_topology = initialize_tpu()
        self.assertIsInstance(serialized_topology, bytes, "Serialized topology should be bytes inside tf.function.")
    except Exception as e:
        self.fail(f"Initialization inside tf.function failed with exception: {e}")

