def test_multiple_dependencies(self):
    a = tf.Variable(0)
    b = tf.Variable(1)

    def todo_if_true():
        incr_a = a.assign_add(1)
        incr_b = b.assign_add(1)
        with tf.control_dependencies([incr_a, incr_b]):
            return tf.identity(a), tf.identity(b)

    def todo_if_false():
        return tf.identity(a), tf.identity(b)

    g = tf.cond(tf.constant(True), todo_if_true, todo_if_false)
    init = tf.compat.v1.global_variables_initializer()

    with tf.compat.v1.Session() as sess:
        sess.run(init)
        result_a, result_b = sess.run(g)
        self.assertEqual(result_a, 1, "The value of a should be 1 since the condition is True")
        self.assertEqual(result_b, 2, "The value of b should be 2 since the condition is True")

def test_assert_shapes_dependency(self):
    @tf.function
    def my_func(x):
        with tf.control_dependencies([tf.debugging.assert_shapes([(x, (2,))])]):
            return x + 2

    result = my_func([1, 2])
    self.assertTrue(tf.reduce_all(tf.equal(result, [3, 4])), "The result should be [3, 4]")

