def test_trace_with_check_inputs(self):
    def simple_fn(x):
        return torch.neg(x)

    example_input = torch.rand(3, 3)
    check_inputs = [(torch.rand(3, 3)), (torch.rand(3, 3))]
    traced_fn = torch.jit.trace(simple_fn, example_input, check_inputs=check_inputs)

    # Check if the traced function produces the same output for check inputs
    for check_input in check_inputs:
        output = traced_fn(check_input)
        expected_output = simple_fn(check_input)
        self.assertTrue(torch.allclose(output, expected_output))

