def test_trace_simple_function(self):
    def simple_fn(x):
        return torch.neg(x)

    example_input = torch.rand(3, 3)
    traced_fn = torch.jit.trace(simple_fn, example_input)

    # Check if the traced function produces the same output
    output = traced_fn(example_input)
    expected_output = simple_fn(example_input)
    self.assertTrue(torch.allclose(output, expected_output))

def test_trace_with_kwargs(self):
    def function_with_kwargs(x, scale=1.0):
        return x * scale

    example_input = torch.tensor([1.0, 2.0, 3.0])
    example_kwargs = {'scale': 2.0}
    traced_function = torch.jit.trace(function_with_kwargs, example_input, example_kwarg_inputs=example_kwargs)
