def test_trace_with_infer_size(self):
    def fn_to_jit(a, b):
        shape = torch._C._infer_size(a.size(), b.size())
        return torch.ones(shape).sum()

    a = torch.rand(3, 3)
    b = torch.rand(3, 3)
    traced_fn = torch.jit.trace(fn_to_jit, (a, b))
    self.assertTrue(torch.allclose(traced_fn(a, b), fn_to_jit(a, b)))

