class TestModelConversion(unittest.TestCase):
    def test_model_conversion_script(self):
        class Concat(nn.Module):
            def forward(self, x):
                return torch.cat(x, 1)

        class Net(nn.Module):
            def __init__(self):
                super().__init__()
                self.conv1 = nn.Conv2d(3, 16, 3, 1)
                self.conv2 = nn.Conv2d(16, 32, 3, 1)

            def forward(self, x):
                y = self.conv1(x)
                y = self.conv2(y)
                z = self.conv1(x)
                z = self.conv2(z)
                return (y, z)

        net = nn.Sequential(
            Net(),
            Concat()
        )
        scripted_net = torch.jit.script(net)
        x = torch.randn(1, 3, 224, 224)
        output = scripted_net(x)
        self.assertEqual(len(output), 2)
        self.assertEqual(output[0].shape, (1, 32, 220, 220))
        self.assertEqual(output[1].shape, (1, 32, 220, 220))

