target_test:
class TestTensorShapeManipulation(unittest.TestCase):
    def test_tensor_shape_script(self):
        @torch.jit.script
        def _forward_impl(x):
            new_shape = (x.shape[0], 2 * x.shape[1])
            x2 = torch.empty(size=new_shape)
            x2[:, ::2] = x
            x2[:, 1::2] = x + 1
            return x2
        class Foo(nn.Module):
            def forward(self, x):
                return _forward_impl(x)
        x = torch.randn((3, 5))
        foo = Foo()
        scripted_foo = torch.jit.script(foo)
        output = scripted_foo(x)
        self.assertEqual(output.shape, (3, 10))

