    @contextmanager
    def no_dispatch():
        guard = _DisableTorchDispatch()
        try:
            yield
        finally:
            del guard

    class TestTensor(torch.Tensor):
        @classmethod
        def __torch_dispatch__(cls, func, types, args=(), kwargs=None):
            with no_dispatch():
                return func(*args, **kwargs)

    with enable_python_mode(TestTensor):
        loaded_tensor = torch.load(self.filename)
    self.assertTrue(torch.equal(self.tensor, loaded_tensor))

