target_test:
def test_mm_script_module(self):
    @torch.jit.script
    def script_fn(x):
        return torch.neg(x)

    class ScriptMod(torch.jit.ScriptModule):
        def __init__(self):
            super(ScriptMod, self).__init__()
            self.param = torch.nn.Parameter(torch.rand(4, 3))

        @torch.jit.script_method
        def forward(self, x):
            return script_fn(torch.mm(x, self.param))

    sm = ScriptMod()
    x = torch.rand(3, 3)
    result = sm.forward(x)
    expected = torch.neg(torch.mm(x, sm.param))
    self.assertTrue(torch.equal(result, expected), f"Expected {expected}, but got {result}")

