def test_integration_with_grid_search_cv(self):
    X, y = load_iris(return_X_y=True)
    model = DecisionTreeClassifier()
    params = {'criterion': ['gini', 'entropy']}
    cv = KFold(3)

    def custom_scorer(y_true, y_pred, actual_scorer):
        score = np.nan
        try:
            score = actual_scorer(y_true, y_pred)
        except Exception:
            pass
        return score

    acc_scorer = make_scorer(custom_scorer, actual_scorer=accuracy_score)
    auc_scorer = make_scorer(custom_scorer, actual_scorer=roc_auc_score, needs_threshold=True)

    scoring = {"roc_auc": auc_scorer, "accuracy": acc_scorer}
    grid_search = GridSearchCV(model, param_grid=params, cv=cv, scoring=scoring, refit="roc_auc")
    grid_search.fit(X, y)

    self.assertIsNotNone(grid_search.best_estimator_)

