def test_random_state_reproducibility(self):
    rs1 = ShuffleSplit(n_splits=5, test_size=0.25, random_state=42)
    rs2 = ShuffleSplit(n_splits=5, test_size=0.25, random_state=42)
    splits1 = list(rs1.split(self.X))
    splits2 = list(rs2.split(self.X))
    for (train_index1, test_index1), (train_index2, test_index2) in zip(splits1, splits2):
