class TestLeaveOneOut(unittest.TestCase):

    def setUp(self):
        self.X = np.array([[1, 2], [3, 4], [5, 6]])
        self.y = np.array([1, 2, 3])
        self.loo = LeaveOneOut()

    def test_get_n_splits(self):
        n_splits = self.loo.get_n_splits(self.X)
        self.assertEqual(n_splits, len(self.X))

    def test_split(self):
        expected_train_indices = [[1, 2], [0, 2], [0, 1]]
        expected_test_indices = [[0], [1], [2]]
        for i, (train_index, test_index) in enumerate(self.loo.split(self.X)):
            with self.subTest(i=i):
                np.testing.assert_array_equal(train_index, expected_train_indices[i])
                np.testing.assert_array_equal(test_index, expected_test_indices[i])

    def test_split_with_y(self):
        expected_train_indices = [[1, 2], [0, 2], [0, 1]]
        expected_test_indices = [[0], [1], [2]]
        for i, (train_index, test_index) in enumerate(self.loo.split(self.X, self.y)):
            with self.subTest(i=i):
                np.testing.assert_array_equal(train_index, expected_train_indices[i])
                np.testing.assert_array_equal(test_index, expected_test_indices[i])

    def test_repr(self):
        self.assertEqual(repr(self.loo), "LeaveOneOut()")

