import unittest
from sklearn.utils.validation import check_consistent_length
import numpy as np


class TestCheckConsistentLength(unittest.TestCase):

    def test_consistent_lengths(self):
        X = [1, 2, 3]
        y = [4, 5, 6]
        sample_weight = [0.1, 0.2, 0.3]
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")

    def test_inconsistent_lengths(self):
        X = [1, 2, 3]
        y = [4, 5]
        sample_weight = [0.1, 0.2, 0.3]
        with self.assertRaises(ValueError):
            check_consistent_length(X, y, sample_weight)

    def test_none_input(self):
        X = [1, 2, 3]
        y = None
        sample_weight = [0.1, 0.2, 0.3]
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")

    def test_empty_input(self):
        X = []
        y = []
        sample_weight = []
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")

    def test_single_element_input(self):
        X = [1]
        y = [2]
        sample_weight = [0.1]
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")

    def test_different_types(self):
        X = np.array([1, 2, 3])
        y = [4, 5, 6]
        sample_weight = (0.1, 0.2, 0.3)
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")

    def test_mixed_none_and_empty(self):
        X = None
        y = []
        sample_weight = []
        try:
            check_consistent_length(X, y, sample_weight)
        except ValueError:
            self.fail("check_consistent_length raised ValueError unexpectedly!")


