def test_scaling_with_numpy(self):
    # Test scaling with numpy for comparison
    def numpy_minmax(X):
        xmin = X.min(axis=0)
        return (X - xmin) / (X.max(axis=0) - xmin)

    np.random.seed(123)
    X = np.random.rand(100, 2) * 100
    numpy_scaled = numpy_minmax(X)
    sklearn_scaled = MinMaxScaler().fit_transform(X)
    np.testing.assert_almost_equal(numpy_scaled, sklearn_scaled, decimal=5)

