def test_dot_grad(self):
    # Test gradient of dot product
    def f(x, y):
        return jnp.sum(lax.dot(x, y))

    grad_f = jax.grad(f, argnums=(0, 1))
    grad_x, grad_y = grad_f(self.x, self.y)

    expected_grad_x = jax.grad(lambda x: jnp.sum(jnp.dot(x, self.y)))(self.x)
    expected_grad_y = jax.grad(lambda y: jnp.sum(jnp.dot(self.x, y)))(self.y)

    self.assertTrue(jnp.allclose(grad_x, expected_grad_x), f"Expected {expected_grad_x}, but got {grad_x}")
    self.assertTrue(jnp.allclose(grad_y, expected_grad_y), f"Expected {expected_grad_y}, but got {grad_y}")

