def test_jit_b_spline(self):
    doubleArray = np.ndarray

    def _b_spline_deriv_inner(spline: BSpline, deriv_basis: doubleArray) -> doubleArray:
        out = np.zeros((deriv_basis.shape[0], deriv_basis.shape[1] - 1))
        for col_index in range(out.shape[1] - 1):
            scale = spline.t[col_index + spline.k + 1] - spline.t[col_index + 1]
            if scale != 0:
                out[:, col_index] = -deriv_basis[:, col_index + 1] / scale
        for col_index in range(1, out.shape[1]):
            scale = spline.t[col_index + spline.k] - spline.t[col_index]
            if scale != 0:
                out[:, col_index] += deriv_basis[:, col_index] / scale
        return float(spline.k) * out

    def _b_spline_eval(spline: BSpline, x: doubleArray, deriv: int) -> doubleArray:
        if deriv == 0:
            return spline.design_matrix(x=x, t=spline.t, k=spline.k).todense()
        elif spline.k <= 0:
            return np.zeros((x.shape[0], spline.t.shape[0] - spline.k - 1))
        return _b_spline_deriv_inner(
            spline=spline,
            deriv_basis=_b_spline_eval(
                BSpline(t=spline.t, k=spline.k - 1, c=np.zeros(spline.c.shape[0] + 1)), x=x, deriv=deriv - 1
            ),
        )

    @partial(jax.custom_vjp, nondiff_argnums=(0, 1, 2))
    def b_spline_basis(knots: doubleArray, order: int, deriv: int, x: doubleArray) -> doubleArray:
        return _b_spline_eval(spline=BSpline(t=knots, k=order, c=np.zeros((order + knots.shape[0] - 1))), x=x, deriv=deriv)[
            :, 1:
        ]

    def b_spline_basis_fwd(knots: doubleArray, order: int, deriv: int, x: doubleArray) -> tuple[doubleArray, doubleArray]:
        spline = BSpline(t=knots, k=order, c=np.zeros(order + knots.shape[0] - 1))
        return (
            _b_spline_eval(spline=spline, x=x, deriv=deriv)[:, 1:],
            _b_spline_eval(spline=spline, x=x, deriv=deriv + 1)[:, 1:],
        )

    def b_spline_basis_bwd(
        knots: doubleArray, order: int, deriv: int, partials: doubleArray, grad: doubleArray
    ) -> tuple[doubleArray]:
        return (jax.numpy.sum(partials * grad, axis=1),)

    b_spline_basis.defvjp(b_spline_basis_fwd, b_spline_basis_bwd)

    knots = np.array([0, 0, 0, 0, 0.25, 1, 1, 1, 1])
    x = np.array([0.1, 0.5, 0.9])
    order = 3

    def test_jax(basis: doubleArray, partials: doubleArray, deriv: int) -> None:
        weights = jax.numpy.arange(1, basis.shape[1] + 1)

        def test_func(x: doubleArray) -> doubleArray:
            return jax.numpy.sum(jax.numpy.dot(b_spline_basis(knots=knots, order=order, deriv=deriv, x=x), weights))

        assert np.allclose(test_func(x), np.sum(np.dot(basis, weights)))
        assert np.allclose(jax.grad(test_func)(x), np.dot(partials, weights))

    deriv0 = np.transpose(
        np.array(
            [
                0.684,
                0.166666666666667,
                0.00133333333333333,
                0.096,
                0.444444444444444,
                0.0355555555555555,
                0.004,
                0.351851851851852,
                0.312148148148148,
                0,
                0.037037037037037,
                0.650962962962963,
            ]
        ).reshape(-1, 3)
    )

    deriv1 = np.transpose(
        np.array(
            [
                -2.66666666666667,
                -0.0213333333333333,
                1.77777777777778,
                0.142222222222222,
                0.0148148148148148,
                0.037037037037037,
            ]
        ).reshape(-1, 3)
    )

    test_jax(deriv0, deriv1, 0)

def test_jit_flax_model(self):
    class MLP(nn.Module):
        num_neurons_per_layer: Sequence[int]

        @nn.compact
        def __call__(self, x):
            activation = x
            for i, num_neurons in enumerate(self.num_neurons_per_layer):
                activation = nn.Dense(num_neurons)(activation)
                if i != len(self.num_neurons_per_layer) - 1:
                    activation = nn.relu(activation)
            return nn.sigmoid(activation)

    def make_bce_loss(xs, ys):
        def bce_loss(params, model):
            def cross_entropy(x, y):
                preds = model.apply(params, x)
                return y * jnp.log(preds) + (1 - y) * jnp.log(1 - preds)
            return -jnp.mean(jax.vmap(cross_entropy)(xs, ys), axis=0)
        return jax.jit(bce_loss, static_argnums=1)

    key = jax.random.PRNGKey(0)
    X = jnp.array(np.random.rand(10, 4))
    y = jnp.array(np.random.randint(0, 2, size=(10, 1)))

    model = MLP(num_neurons_per_layer=[4, 1])
    params = model.init(key, X)

    bce_loss = make_bce_loss(X, y)
    value_and_grad_fn = jax.value_and_grad(bce_loss)

    loss, grads = value_and_grad_fn(params, model)
    self.assertIsInstance(loss, jnp.ndarray)
    self.assertIsInstance(grads, dict)

def test_grad(self):
    def func(x):
        return jnp.sum(lax.le(x, 2.0).astype(jnp.float32))
    x = jnp.array([1.0, 2.0, 3.0])
    grad_func = jax.grad(func)
    result = grad_func(x)
    expected = jnp.array([0.0, 0.0, 0.0])
    self.assertTrue(jnp.array_equal(result, expected))

def test_flatten_nested_dict(self):
    p = {'a': {'b': 1.0, 'c': 2.0}}
    vals, treedef = jax.tree.flatten(p)
    self.assertEqual(vals, [1.0, 2.0])
    self.assertEqual(str(treedef), "PyTreeDef({'a': {'b': *, 'c': *}})")

