class TestSparkXGBRegressorModelCopy(unittest.TestCase):

    @classmethod
    def setUpClass(cls):
        cls.spark = SparkSession.builder.master("local[1]").appName("XGBoostTest").getOrCreate()
        cls.spark.sparkContext.setLogLevel("ERROR")

    @classmethod
    def tearDownClass(cls):
        cls.spark.stop()

    def setUp(self):
        # Create a simple DataFrame for testing
        self.data = [
            Row(label=1.0, features=Vectors.dense([0.0, 1.0, 2.0])),
            Row(label=0.0, features=Vectors.dense([1.0, 2.0, 3.0])),
            Row(label=1.0, features=Vectors.dense([2.0, 3.0, 4.0])),
            Row(label=0.0, features=Vectors.dense([3.0, 4.0, 5.0]))
        ]
        self.df = self.spark.createDataFrame(self.data)

        # Initialize the SparkXGBRegressor
        self.regressor = SparkXGBRegressor(
            features_col="features",
            label_col="label",
            num_workers=1
        )

        # Fit the model
        self.model = self.regressor.fit(self.df)

    def test_copy_model(self):
        # Copy the model with extra parameters
        extra_params = {"max_depth": 5}
        copied_model = self.model.copy(extra_params)

        # Check that the copied model has the same UID
        self.assertEqual(self.model.uid, copied_model.uid)

        # Check that the copied model has the same parameters as the original
        for param in self.model.extractParamMap():
            self.assertEqual(self.model.getOrDefault(param), copied_model.getOrDefault(param))

        # Check that the extra parameters are applied to the copied model
        self.assertEqual(copied_model.getOrDefault("max_depth"), 5)

