class TestSparkXGBRegressorModelCopy(unittest.TestCase):

    @classmethod
    def setUpClass(cls):
        cls.spark = SparkSession.builder.appName("XGBoostUnitTest").master("local[1]").getOrCreate()
        cls.data = cls.spark.createDataFrame([
            (1.0, 1.0),
            (2.0, 2.0),
            (3.0, 3.0),
            (4.0, 4.0)
        ], ["features", "label"])
        cls.regressor = SparkXGBRegressor(max_depth=2, n_estimators=10)
        cls.model = cls.regressor.fit(cls.data)

    @classmethod
    def tearDownClass(cls):
        cls.spark.stop()

    def test_copy_without_extra(self):
        model_copy = self.model.copy()
        self.assertIsNot(self.model, model_copy)
        self.assertEqual(self.model.uid, model_copy.uid)
        self.assertEqual(self.model.getOrDefault("max_depth"), model_copy.getOrDefault("max_depth"))

    def test_copy_with_extra(self):
        extra_params = {"max_depth": 3}
        model_copy = self.model.copy(extra=extra_params)
        self.assertIsNot(self.model, model_copy)
        self.assertEqual(self.model.uid, model_copy.uid)
        self.assertEqual(model_copy.getOrDefault("max_depth"), 3)

