class TestSparkXGBRankerModel(unittest.TestCase):

    @classmethod
    def setUpClass(cls):
        cls.spark = SparkSession.builder \
            .appName("XGBoost Spark Test") \
            .master("local[*]") \
            .getOrCreate()

    @classmethod
    def tearDownClass(cls):
        cls.spark.stop()

    def setUp(self):
        self.temp_dir = tempfile.mkdtemp()

    def tearDown(self):
        for root, dirs, files in os.walk(self.temp_dir, topdown=False):
            for name in files:
                os.remove(os.path.join(root, name))
            for name in dirs:
                os.rmdir(os.path.join(root, name))
        os.rmdir(self.temp_dir)

    def test_get_booster(self):
        data = [(0, 1.0, 0.1, 0.2, 0.3),
                (0, 0.0, 0.2, 0.1, 0.4),
                (1, 0.0, 0.3, 0.2, 0.5),
                (1, 1.0, 0.4, 0.3, 0.6)]
        columns = ["group", "label", "feature1", "feature2", "feature3"]
        df = self.spark.createDataFrame(data, columns)

        ranker = SparkXGBRanker(max_depth=2, objective='rank:pairwise', num_round=10)
        model = ranker.fit(df)

        booster = model.get_booster()
        self.assertIsInstance(booster, Booster)

        dmatrix = xgb.DMatrix(np.array([[0.1, 0.2, 0.3], [0.2, 0.1, 0.4]]))
        predictions = booster.predict(dmatrix)
        self.assertEqual(predictions.shape[0], 2)

