def test_with_early_stopping(self):
    params = {'objective': 'binary:logistic', 'eval_metric': 'logloss'}
    evals = [(self.dtrain, 'train')]
    result = train(self.client, params, self.dtrain, num_boost_round=10, evals=evals, early_stopping_rounds=5)
    self.assertIn('booster', result)
    self.assertIn('history', result)

def test_with_callbacks(self):
    def callback(env):
        print(f"Iteration {env.iteration}")

    params = {'objective': 'binary:logistic', 'eval_metric': 'logloss'}
    result = train(self.client, params, self.dtrain, num_boost_round=10, callbacks=[callback])
    self.assertIn('booster', result)
    self.assertIn('history', result)

