class TestDaskXGBRFRegressorSetParams(unittest.TestCase):
    @classmethod
    def setUpClass(cls):
        cls.client = Client(n_workers=2, threads_per_worker=2, processes=False)

    @classmethod
    def tearDownClass(cls):
        cls.client.close()

    def setUp(self):
        self.X = da.from_array(np.array([[1, 2, 3, 4], [1, 3, 4, 2]]), chunks=(2, 4))
        self.y = da.from_array(np.array([1, 0]), chunks=(2,))
        self.model = DaskXGBRFRegressor(client=self.client)

    def test_set_params(self):
        params = {
            'max_depth': 5,
            'learning_rate': 0.1,
            'n_estimators': 10,
            'objective': 'reg:squarederror'
        }
        self.model.set_params(**params)

        self.assertEqual(self.model.get_params()['max_depth'], 5)
        self.assertEqual(self.model.get_params()['learning_rate'], 0.1)
        self.assertEqual(self.model.get_params()['n_estimators'], 10)
        self.assertEqual(self.model.get_params()['objective'], 'reg:squarederror')

        self.model.fit(self.X, self.y)
        preds = self.model.predict(self.X)
        self.assertEqual(preds.shape[0], self.y.shape[0])

