import unittest
from dask.distributed import Client, LocalCluster
from xgboost.dask import DaskXGBRFRegressor
import dask.array as da


class TestDaskXGBRFRegressorSetParams(unittest.TestCase):

    @classmethod
    def setUpClass(cls):
        cls.cluster = LocalCluster(n_workers=2, threads_per_worker=2)
        cls.client = Client(cls.cluster)

    @classmethod
    def tearDownClass(cls):
        cls.client.close()
        cls.cluster.close()

    def setUp(self):
        self.X = da.random.random((100, 10), chunks=(50, 10))
        self.y = da.random.random(100, chunks=50)

    def test_set_params(self):
        model = DaskXGBRFRegressor()
        params = {
            'max_depth': 5,
            'learning_rate': 0.1,
            'n_estimators': 50,
            'subsample': 0.8,
            'colsample_bytree': 0.8
        }
        model.set_params(**params)
        for param, value in params.items():
            self.assertEqual(getattr(model, param), value)
        model.fit(self.client, self.X, self.y)
        preds = model.predict(self.client, self.X)
        self.assertEqual(preds.shape[0], self.X.shape[0])

    def test_set_params_invalid(self):
        model = DaskXGBRFRegressor()
        with self.assertRaises(ValueError):
            model.set_params(non_existent_param=1)


if __name__ == '__main__':
    unittest.main()

